## Generated Code

**Step 1 — Requirements:** Deep merge two objects, where the second object's properties override the first. Nested objects should be merged recursively. Arrays should be replaced (not concatenated).

**Step 2 — Structure:** A recursive function that handles nested objects and returns a new merged object without mutating inputs.

**Step 3 — Implementation:**

```typescript
type DeepPartial<T> = {
  [K in keyof T]?: T[K] extends object ? DeepPartial<T[K]> : T[K];
};

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

export function deepMerge<T extends Record<string, unknown>>(
  base: T,
  override: DeepPartial<T>
): T {
  const result = { ...base };

  for (const key of Object.keys(override) as (keyof T)[]) {
    const overrideVal = override[key];
    const baseVal = base[key];

    if (isPlainObject(overrideVal) && isPlainObject(baseVal)) {
      result[key] = deepMerge(
        baseVal as Record<string, unknown>,
        overrideVal as Record<string, unknown>
      ) as T[keyof T];
    } else if (overrideVal !== undefined) {
      result[key] = overrideVal as T[keyof T];
    }
  }

  return result;
}
```

**Step 4 — Review:**
- Does not mutate either input ✓
- Arrays are replaced (not merged), which is the typical desired behaviour ✓
- Only plain objects are recursed into (not class instances, Date, etc.) ✓
- Type-safe: the return type matches the base object's type ✓

**Usage:**

```typescript
const base = { a: 1, b: { c: 2, d: 3 } };
const override = { b: { c: 99 } };
const result = deepMerge(base, override);
// { a: 1, b: { c: 99, d: 3 } }
```
